    }

    for (const trans of (item.translations || [])) {
      const localeId = trans.translations_id;

      let margin = 0;
      if (marginMatchedException && marginMatchedException.translations) {
        const et = marginMatchedException.translations.find(t => t.translations_id === localeId);
        margin = et ? et.exception_margin : 0;
      } else if (defaultMarginPreset && defaultMarginPreset.rental_car_margin_translation) {
        const pt = defaultMarginPreset.rental_car_margin_translation.find(t => t.translations_id === localeId);
        margin = pt ? pt.margin : 0;
      }

      const currentExchangeRateId = trans.exchange_rate;
      let rateValue = 1;
      if (currentExchangeRateId) {
        const r = rates.find(rate => rate.id === currentExchangeRateId);
        rateValue = r ? parseFloat(r.rate) : 1;
      }

      const sellPrice = buyPrice != null ? roundHalf(buyPrice * rateValue * (1 + margin / 100)) : null;

      updates.push({ 
        id: trans.id, 
        margin: margin, 
        sell_price: sellPrice 
      });
    }
  }

  return updates;
};

